11	func (r *Reconciler) reconcileIstioCSRDeployment(istiocsr *v1alpha1.IstioCSR, istioCSRCreateRecon bool) error {
12		if err := validateIstioCSRConfig(istiocsr); err != nil {
13			return common.NewIrrecoverableError(err, "%s/%s configuration validation failed", istiocsr.GetNamespace(), istiocsr.GetName())
14		}
15	
16		// if user has set custom labels to be added to all resources created by the controller
17		// merge it with the controller's own default labels.
18		resourceLabels := make(map[string]string)
19		if istiocsr.Spec.ControllerConfig != nil && len(istiocsr.Spec.ControllerConfig.Labels) != 0 {
20			maps.Copy(resourceLabels, istiocsr.Spec.ControllerConfig.Labels)
21		}
22		maps.Copy(resourceLabels, controllerDefaultResourceLabels)
23	
24		if err := r.createOrApplyNetworkPolicies(istiocsr, resourceLabels, istioCSRCreateRecon); err != nil {
25			r.log.Error(err, "failed to reconcile network policy resources")
26			return err
27		}
28	
29		if err := r.createOrApplyServices(istiocsr, resourceLabels, istioCSRCreateRecon); err != nil {
30			r.log.Error(err, "failed to reconcile service resource")
31			return err
32		}
33	
34		if err := r.createOrApplyServiceAccounts(istiocsr, resourceLabels, istioCSRCreateRecon); err != nil {
35			r.log.Error(err, "failed to reconcile serviceaccount resource")
36			return err
37		}
38	
39		if err := r.createOrApplyRBACResource(istiocsr, resourceLabels, istioCSRCreateRecon); err != nil {
40			r.log.Error(err, "failed to reconcile rbac resources")
41			return err
42		}
43	
44		if err := r.createOrApplyCertificates(istiocsr, resourceLabels, istioCSRCreateRecon); err != nil {
45			r.log.Error(err, "failed to reconcile certificate resource")
46			return err
47		}
48	
49		if err := r.createOrApplyDeployments(istiocsr, resourceLabels, istioCSRCreateRecon); err != nil {
50			r.log.Error(err, "failed to reconcile deployment resource")
51			return err
52		}
53	
54		if addProcessedAnnotation(istiocsr) {
55			if err := r.UpdateWithRetry(r.ctx, istiocsr); err != nil {
56				return fmt.Errorf("failed to update processed annotation to %s/%s: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
57			}
58		}
59	
60		r.log.V(4).Info("finished reconciliation of istiocsr", "namespace", istiocsr.GetNamespace(), "name", istiocsr.GetName())
61		return nil
62	}
