85	// updateStatusObservedState populates and persists the TrustManager status with the observed state.
86	// Returns nil if no changes were needed, otherwise returns an error if the update fails.
87	func (r *Reconciler) updateStatusObservedState(trustManager *v1alpha1.TrustManager) error {
88		changed := false
89	
90		if image := os.Getenv(trustManagerImageNameEnvVarName); trustManager.Status.TrustManagerImage != image {
91			trustManager.Status.TrustManagerImage = image
92			changed = true
93		}
94	
95		if ns := getTrustNamespace(trustManager); trustManager.Status.TrustNamespace != ns {
96			trustManager.Status.TrustNamespace = ns
97			changed = true
98		}
99	
100		if policy := trustManager.Spec.TrustManagerConfig.SecretTargets.Policy; trustManager.Status.SecretTargetsPolicy != policy {
101			trustManager.Status.SecretTargetsPolicy = policy
102			changed = true
103		}
104	
105		if policy := trustManager.Spec.TrustManagerConfig.DefaultCAPackage.Policy; trustManager.Status.DefaultCAPackagePolicy != policy {
106			trustManager.Status.DefaultCAPackagePolicy = policy
107			changed = true
108		}
109	
110		if policy := trustManager.Spec.TrustManagerConfig.FilterExpiredCertificates; trustManager.Status.FilterExpiredCertificatesPolicy != policy {
111			trustManager.Status.FilterExpiredCertificatesPolicy = policy
112			changed = true
113		}
114	
115		if !changed {
116			return nil
117		}
118	
119		return r.updateStatus(r.ctx, trustManager)
120	}
