// computeTrustedCABundleHash reads the CNO-injected CA bundle and returns its
// SHA-256 content hash. Returns ("", nil) if the ConfigMap does not exist yet,
// allowing reconciliation to proceed without the hash annotation.
func (r *Reconciler) computeTrustedCABundleHash() (string, error) {
	caBundle, err := r.readTrustedCABundle()
	if err != nil {
		return "", err
	}
	return computeCABundleHash(caBundle), nil
}
```

