// stampCABundleHash sets the CA bundle content hash as a pod template annotation
// on the deployment. Changing this annotation value triggers a rolling restart
// because Kubernetes treats it as a pod template spec change.
func stampCABundleHash(deployment *appsv1.Deployment, caBundleHash string) {
	if caBundleHash == "" {
		return
	}
	if deployment.Spec.Template.Annotations == nil {
		deployment.Spec.Template.Annotations = make(map[string]string)
	}
	deployment.Spec.Template.Annotations[caBundleHashAnnotation] = caBundleHash
}
```

