// podTemplateAnnotationChanged checks whether a specific annotation on the pod
// template differs between the desired and fetched deployments.
func podTemplateAnnotationChanged(desired, fetched *appsv1.Deployment, key string) bool {
	desiredVal := desired.Spec.Template.Annotations[key]
	fetchedVal := fetched.Spec.Template.Annotations[key]
	return desiredVal != fetchedVal
}
